column.value:
{
  "pageDescription": "Sterilization",
  "dataPoints": {
    "sterilizationDetails": {
      "method": {"type": "choice", "label": "Sterilization Method", "options": ["Autoclave", "Filtration", "UV irradiation", "Chemical"], "required": true},
      "temperature": {"type": "number", "label": "Temperature (C)", "required": false},
      "pressure": {"type": "number", "label": "Pressure (psi)", "required": false},
      "duration": {"type": "number", "label": "Duration (minutes)", "required": true}
    },
    "operatorDetails": {
      "operator": {"type": "text", "label": "Operator", "required": true},
      "dateTime": {"type": "dateTime", "label": "Date/Time", "required": true},
      "equipmentId": {"type": "text", "label": "Equipment ID", "required": false}
    },
    "verification": {
      "indicatorResult": {"type": "choice", "label": "Indicator Result", "options": ["Pass", "Fail", "Pending"], "required": true},
      "notes": {"type": "text", "label": "Notes", "required": false}
    }
  },
  "systemActions": ["Link sterilization record to sample/media batch"],
  "nextPage": "Cell Culture"
}

{
  "pageDescription": "Cell Culture (Host Cell Preparation)",
  "dataPoints": {
    "cellDetails": {
      "cellLine": {"type": "choice", "label": "Cell Line", "options": ["Vero", "HEK293", "MDCK", "BHK-21", "CHO", "HeLa", "Other"], "required": true},
      "cellLineOther": {"type": "text", "label": "Other Cell Line", "required": false},
      "passageNumber": {"type": "number", "label": "Passage Number", "required": true}
    },
    "growthConditions": {
      "mediaUsed": {"type": "text", "label": "Media Used", "required": true},
      "temperature": {"type": "number", "label": "Temperature (C)", "required": true},
      "co2Percentage": {"type": "number", "label": "CO2 (%)", "required": false},
      "incubatorId": {"type": "text", "label": "Incubator ID", "required": true}
    },
    "cultureMetadata": {
      "startDate": {"type": "date", "label": "Start Date", "required": true},
      "seedingDensity": {"type": "text", "label": "Seeding Density", "required": false},
      "flaskType": {"type": "choice", "label": "Flask/Plate Type", "options": ["T25", "T75", "T175", "6-well", "12-well", "24-well", "96-well"], "required": true},
      "operator": {"type": "text", "label": "Operator", "required": true}
    }
  },
  "systemActions": ["Create cell culture batch", "Link to sample"],
  "nextPage": "Cell Culture QC"
}

{
  "pageDescription": "Cell Culture Quality Control",
  "dataPoints": {
    "viabilityCheck": {
      "viabilityMethod": {"type": "choice", "label": "Viability Method", "options": ["Trypan Blue", "MTT Assay", "Flow Cytometry", "Visual"], "required": true},
      "viabilityPercentage": {"type": "number", "label": "Viability (%)", "required": true},
      "cellCount": {"type": "text", "label": "Cell Count", "required": false}
    },
    "sterilityCheck": {
      "sterilityResult": {"type": "choice", "label": "Sterility Result", "options": ["Pass", "Fail", "Pending"], "required": true},
      "contaminationType": {"type": "choice", "label": "Contamination Type (if any)", "options": ["None", "Bacterial", "Fungal", "Mycoplasma", "Unknown"], "required": false}
    },
    "qcDecision": {
      "qcStatus": {"type": "choice", "label": "QC Status", "options": ["Pass", "Fail", "Conditional Pass"], "required": true},
      "qcDate": {"type": "date", "label": "QC Date", "required": true},
      "qcOperator": {"type": "text", "label": "QC Operator", "required": true},
      "remarks": {"type": "text", "label": "Remarks", "required": false}
    }
  },
  "systemActions": ["Log QC results", "Block progression if failed"],
  "nextPage": "Virus Culture Inoculation"
}

{
  "pageDescription": "Virus Culture Inoculation",
  "dataPoints": {
    "virusDetails": {
      "virusStrain": {"type": "text", "label": "Virus Strain", "required": true},
      "virusSource": {"type": "choice", "label": "Virus Source", "options": ["Clinical isolate", "Reference strain", "Seed stock"], "required": true},
      "moi": {"type": "text", "label": "MOI (Multiplicity of Infection)", "required": false}
    },
    "inoculationDetails": {
      "inoculationDate": {"type": "dateTime", "label": "Inoculation Date/Time", "required": true},
      "inoculationVolume": {"type": "text", "label": "Inoculation Volume", "required": false},
      "adsorptionTime": {"type": "number", "label": "Adsorption Time (min)", "required": false}
    },
    "cultureConditions": {
      "temperature": {"type": "number", "label": "Incubation Temp (C)", "required": true},
      "co2Percentage": {"type": "number", "label": "CO2 (%)", "required": false},
      "incubatorId": {"type": "text", "label": "Incubator ID", "required": true},
      "operator": {"type": "text", "label": "Operator", "required": true}
    }
  },
  "systemActions": ["Create virus culture batch", "Link to original sample"],
  "nextPage": "Imaging / Analysis"
}

{
  "pageDescription": "Imaging / Analysis (Dark Room / Fluorescence)",
  "dataPoints": {
    "imagingDetails": {
      "imagingMethod": {"type": "choice", "label": "Imaging Method", "options": ["Light microscopy", "Fluorescence", "Phase contrast", "Confocal", "Electron microscopy"], "required": true},
      "magnification": {"type": "choice", "label": "Magnification", "options": ["4x", "10x", "20x", "40x", "100x"], "required": false},
      "imagingDate": {"type": "dateTime", "label": "Imaging Date/Time", "required": true}
    },
    "observations": {
      "cpeObserved": {"type": "choice", "label": "CPE Observed", "options": ["None", "Minimal (1+)", "Moderate (2+)", "Significant (3+)", "Complete (4+)"], "required": true},
      "confluency": {"type": "number", "label": "Confluency (%)", "required": false},
      "observations": {"type": "text", "label": "Observations", "required": false}
    },
    "imageUpload": {
      "images": {"type": "file", "label": "Upload Images", "accept": "image/*", "multiple": true, "required": false},
      "operator": {"type": "text", "label": "Operator", "required": true}
    }
  },
  "systemActions": ["Store image data", "Link to culture batch"],
  "nextPage": "Culture Maintenance"
}

{
  "pageDescription": "Culture Feeding & Maintenance",
  "dataPoints": {
    "maintenanceAction": {
      "actionType": {"type": "choice", "label": "Action Type", "options": ["Media change", "Feeding", "Passage", "Harvest", "Other"], "required": true},
      "mediaVolume": {"type": "text", "label": "Media Volume", "required": false}
    },
    "reagentsUsed": {
      "reagents": {"type": "text", "label": "Reagents Used", "required": false},
      "lotNumbers": {"type": "text", "label": "Lot Numbers", "required": false}
    },
    "scheduleDetails": {
      "dateTime": {"type": "dateTime", "label": "Date/Time", "required": true},
      "nextScheduled": {"type": "dateTime", "label": "Next Scheduled", "required": false},
      "technician": {"type": "text", "label": "Technician", "required": true},
      "notes": {"type": "text", "label": "Notes", "required": false}
    }
  },
  "systemActions": ["Create maintenance log"],
  "nextPage": "Formulation & Packaging"
}

{
  "pageDescription": "Viral Formulation & Packaging",
  "dataPoints": {
    "formulationDetails": {
      "formulationType": {"type": "choice", "label": "Formulation Type", "options": ["Liquid", "Lyophilized", "Frozen"], "required": true},
      "excipients": {"type": "text", "label": "Excipients/Stabilizers", "required": false},
      "concentration": {"type": "text", "label": "Final Concentration", "required": false}
    },
    "productDetails": {
      "productDescription": {"type": "text", "label": "Product Description", "required": true},
      "batchId": {"type": "text", "label": "Batch ID", "required": true},
      "totalVolume": {"type": "text", "label": "Total Volume/Quantity", "required": true}
    },
    "packagingDetails": {
      "containerType": {"type": "choice", "label": "Container Type", "options": ["Vial", "Ampule", "Cryovial", "Tube"], "required": true},
      "fillVolume": {"type": "text", "label": "Fill Volume", "required": true},
      "numberOfUnits": {"type": "number", "label": "Number of Units", "required": true},
      "storageCondition": {"type": "choice", "label": "Storage Condition", "options": ["2-8C", "-20C", "-80C", "-196C (LN2)"], "required": true},
      "packagingDate": {"type": "date", "label": "Packaging Date", "required": true},
      "operator": {"type": "text", "label": "Operator", "required": true}
    }
  },
  "systemActions": ["Link final product batch to sample", "Set status: Viral Processing Completed"],
  "nextPage": "Virus Isolation & Titer"
}

{
  "pageDescription": "Virus Isolation & Titer Measurement",
  "dataPoints": {
    "cultureBatch": {
      "batchReference": {"type": "text", "label": "Culture Batch Reference", "required": true},
      "harvestDate": {"type": "date", "label": "Harvest Date", "required": true}
    },
    "titerMeasurement": {
      "measurementMethod": {"type": "choice", "label": "Measurement Method", "options": ["TCID50", "Plaque assay", "qPCR", "ELISA", "HAU"], "required": true},
      "titerValue": {"type": "text", "label": "Titer Value", "required": true},
      "titerUnit": {"type": "choice", "label": "Titer Unit", "options": ["TCID50/mL", "PFU/mL", "copies/mL", "HAU"], "required": true}
    },
    "measurementDetails": {
      "measurementDate": {"type": "date", "label": "Measurement Date", "required": true},
      "operator": {"type": "text", "label": "Operator", "required": true},
      "notes": {"type": "text", "label": "Notes", "required": false}
    }
  },
  "systemActions": ["Link quantitative data to sample"],
  "nextPage": "Genome Sequencing"
}

{
  "pageDescription": "Viral Genome Sequencing",
  "dataPoints": {
    "sequencingDetails": {
      "platform": {"type": "choice", "label": "Sequencing Platform", "options": ["Illumina", "Oxford Nanopore", "PacBio", "Sanger", "Ion Torrent"], "required": true},
      "libraryPrepMethod": {"type": "text", "label": "Library Prep Method", "required": false},
      "sequencingDate": {"type": "date", "label": "Sequencing Date", "required": true}
    },
    "sequenceFiles": {
      "files": {"type": "file", "label": "Sequence Files", "accept": ".fasta,.fastq,.fa,.fq,.ab1", "multiple": true, "required": false},
      "accessionNumber": {"type": "text", "label": "GenBank Accession (if submitted)", "required": false}
    },
    "qcMetrics": {
      "coverage": {"type": "text", "label": "Coverage", "required": false},
      "quality": {"type": "text", "label": "Quality Score", "required": false},
      "completeness": {"type": "choice", "label": "Genome Completeness", "options": ["Complete", "Near-complete", "Partial"], "required": true},
      "operator": {"type": "text", "label": "Operator", "required": true}
    }
  },
  "systemActions": ["Store genome data", "Link to sample/culture batch"],
  "nextPage": "Seed Virus Production"
}

{
  "pageDescription": "Seed Virus Production",
  "dataPoints": {
    "strainSelection": {
      "selectedStrain": {"type": "text", "label": "Selected Strain", "required": true},
      "strainOrigin": {"type": "text", "label": "Strain Origin", "required": true},
      "passageHistory": {"type": "text", "label": "Passage History", "required": false}
    },
    "selectionCriteria": {
      "criteria": {"type": "text", "label": "Selection Criteria", "required": true},
      "geneticStability": {"type": "choice", "label": "Genetic Stability Confirmed", "options": ["Yes", "No", "Pending"], "required": true},
      "antigenicProfile": {"type": "text", "label": "Antigenic Profile", "required": false}
    },
    "approvalDetails": {
      "approvedBy": {"type": "text", "label": "Approved By", "required": true},
      "approvalDate": {"type": "date", "label": "Approval Date", "required": true},
      "seedLotNumber": {"type": "text", "label": "Seed Lot Number", "required": true},
      "storageLocation": {"type": "text", "label": "Storage Location", "required": true}
    }
  },
  "systemActions": ["Create seed virus record", "Link to sample"],
  "nextPage": "Trial Reference"
}

{
  "pageDescription": "Preclinical & Clinical Trial Reference",
  "dataPoints": {
    "trialPhase": {
      "phase": {"type": "choice", "label": "Trial Phase", "options": ["Preclinical - In vitro", "Preclinical - In vivo", "Clinical Phase I", "Clinical Phase II", "Clinical Phase III", "Clinical Phase IV"], "required": true},
      "trialIdentifier": {"type": "text", "label": "Trial Identifier/Number", "required": false}
    },
    "externalDetails": {
      "institution": {"type": "text", "label": "External Institution", "required": true},
      "principalInvestigator": {"type": "text", "label": "Principal Investigator", "required": false},
      "contactInfo": {"type": "text", "label": "Contact Information", "required": false}
    },
    "timeline": {
      "startDate": {"type": "date", "label": "Start Date", "required": true},
      "endDate": {"type": "date", "label": "End Date", "required": false},
      "status": {"type": "choice", "label": "Status", "options": ["Planned", "In Progress", "Completed", "Terminated", "On Hold"], "required": true}
    },
    "outcome": {
      "outcomeSummary": {"type": "text", "label": "Outcome Summary", "required": false},
      "documentReference": {"type": "text", "label": "Document Reference", "required": false},
      "recordedBy": {"type": "text", "label": "Recorded By", "required": true},
      "recordDate": {"type": "date", "label": "Record Date", "required": true}
    }
  },
  "systemActions": ["Link external reference to seed virus/sample"],
  "nextPage": null
}
